-- Juror Period Auth
-- Status semantics: Completed = final_submitted_at + all projects scored
--                   Editing   = final_submitted_at + edit_enabled
--                   InProgress = some scores, no final_submitted_at
--                   ReadyToSubmit = all scored, no final_submitted_at
--                   NotStarted = pin_hash only (no last_seen_at, no scores)
-- Distribution: current periods ~80% completed, past periods 100% completed


