INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('3b8b2e62-bc66-4c8c-ad14-371049c8204e', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Otonom Sürü İHA (UAV) Takip Sistemi (Takım 1)', 1, '[{"name":"Tuğçe Zorlu","order":1},{"name":"Elif Akbaş","order":2},{"name":"Selin Bilgin","order":3},{"name":"Pınar Cengiz","order":4}]', 'Prof. Sinem Uslu', 'TEKNOFEST', 'Sürü haberleşme protokolleri ve dağıtık görev planlama algoritmaları kullanan çok rotorlu İHA sistemi; GPS-reddedilen ortamlarda hedef takibi ve oluşum koruması sağlar.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('c23aa93d-d7c4-4b82-aee5-2d857b47638c', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Yüksek İrtifa Hibrit Roket Motoru (Takım 2)', 2, '[{"name":"Buse Demirel","order":1},{"name":"Levent Ergün","order":2},{"name":"Selim Filiz","order":3}]', 'Prof. İrem Demirci', 'TEKNOFEST', 'Nitröz oksit ve HTPB yakıt kombinasyonuyla 3000 m irtifaya ulaşan hibrit roket motoru tasarımı; yanma kararlılığı analizi ve geri kazanılabilir iniş sistemi içerir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('1b122688-dc8e-467d-aa9d-16a7c8dbd1a8', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Otonom Sualtı Aracı (AUV) Görüntüleme (Takım 3)', 3, '[{"name":"Ece Gürbüz","order":1},{"name":"Seda Hatipoğlu","order":2},{"name":"Hande Işıklar","order":3},{"name":"Dilan Karadeniz","order":4}]', 'Prof. Berk Gündüz', 'TEKNOFEST', 'Manyetometre ve stereo görüntüyle haritalama yapan otonom sualtı aracı; deniz tabanı incelemesi ve yapay zeka destekli nesne tanıma modülü barındırır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('c900eb14-5b94-461b-ac3d-f2a9075269b6', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'VTOL Sabit Kanatlı Kargo Dronu (Takım 4)', 4, '[{"name":"Hüseyin Yılmaz","order":1},{"name":"Orçun Kaya","order":2},{"name":"Reyhan Demir","order":3}]', 'Prof. Caner Turgut', 'TEKNOFEST', 'Sabit kanatlı uçuş verimliliğini çok rotorlu VTOL kalkış-iniş yeteneğiyle birleştiren kargo dronu; 5 kg yük kapasitesi ve 40 km menzil hedefler.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('ba5787ab-8196-4453-afd3-2e47c5185fb8', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Radar Dalga Sönümleyici Gövde Boyası (Takım 5)', 5, '[{"name":"Gülay Çelik","order":1},{"name":"Orhan Şahin","order":2},{"name":"Adnan Doğan","order":3}]', 'Prof. Ozan Çelebi', 'TEKNOFEST', 'Karbonyl demir ve ferrit nanopartikül katkılamasıyla geliştirilen metamalzeme tabanlı radar sönümleme kaplama; 8-18 GHz bandında 15 dB üzerinde geri saçılım azaltımı sağlar.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('b6718b6b-02a8-444b-a8ec-ff82aad1b946', '308d2708-dbea-41b6-a1c8-da6129445759', 'Çarpışmadan Kaçınan İHA Sürüsü ile Arama-Kurtarma Misyonu', 1, '[{"name":"Yüksel Kılıç","order":1},{"name":"Leyla Aslan","order":2},{"name":"Sevgi Özdemir","order":3}]', 'Prof. Umut Şahin', 'TEKNOFEST', 'Daglik arazide kayip kisi tespiti icin carpismadan kacnan suru algoritmasi ile yonetilen 5 adet quadrotor tasarlanmis; termal goruntuleme ve GPS-reddeden ortamda gorsel-atalet navigasyonu entegre edilmistir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('75baa7d0-6001-4420-a744-5b46e6483201', '308d2708-dbea-41b6-a1c8-da6129445759', 'Denizde Kullanım İçin Biyobozunur Hibrit Roket Yakıtı Geliştirme', 2, '[{"name":"Derya Yıldız","order":1},{"name":"Zehra Koç","order":2},{"name":"Veli Kaplan","order":3},{"name":"Harun Aydın","order":4}]', 'Prof. Zeynep Gül', 'TEKNOFEST', 'Cevresel etkiyi en aza indiren biyobozunur bir hibrit yakit formulasyonu gelistirilmis, su kaynaklarina yakin firlatma operasyonlarinda konvansiyonel polimer oksitleyicilere kiyasla ozgul itis performansi olculmistur.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('35607ef7-b333-4b5b-aa1a-e7ebd1a57d32', '308d2708-dbea-41b6-a1c8-da6129445759', 'Biyolojik Numune Toplama Modüllü Otonom Derin Deniz AUV', 3, '[{"name":"Tayfun Güneş","order":1},{"name":"Selda Türk","order":2},{"name":"Recep Keskin","order":3}]', 'Prof. Korhan Alkan', 'TEKNOFEST', 'Deniz tabaninda biyolojik numune toplama icin tasarlanmis otonom bir sudalti araci gelistirilmis; derinlik-bagimli termal harita rehberliginde hedef tespiti icin YOLOv8-nano modeli kullanilmistir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('accfb911-acf9-481e-a167-d4ba6eaa9aaa', '308d2708-dbea-41b6-a1c8-da6129445759', 'Geri Çekilen Kanat Geçişli VTOL Dronu ile Yük Teslimatı', 4, '[{"name":"Fikri Uslu","order":1},{"name":"Taner Bulut","order":2},{"name":"Fikret Öztürk","order":3},{"name":"Sadık Korkmaz","order":4}]', 'Prof. Deniz Ünal', 'TEKNOFEST', 'Kisametafeli hava tasimaciligi icin kanat-govde gecis mekanizmasina sahip VTOL sabit kanat hibrit bir arac gelistirilmis; gecis manevrasi sirasindaki aerodinamik ve yapisal yukler HesaplamaliAD ile dogrulanmistir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('4edc653f-c0e7-4217-aca1-1c827f8204aa', 'bf4ee98f-1fd2-418d-a62d-8cb5b585f293', 'GNSS-Yoksun Ortamda Görsel-Atalet Odometrisi ile İHA Sürüsü Navigasyonu', 1, '[{"name":"Burhan Çetin","order":1},{"name":"Nihal Bozkurt","order":2},{"name":"Alihan Demirci","order":3}]', 'Prof. Ezgi Doruk', 'TEKNOFEST', 'Sehir ici GNSS karistirma senaryolarinda 4 adet quadrotordan olusan bir suruyu yonlendirmek icin gorsel-atalet odometrisi tabanli dagitik bir navigasyon cercevesi gelistirilmistir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('fd4bc2a1-e69b-4bf2-aab4-5f2da12927de', 'bf4ee98f-1fd2-418d-a62d-8cb5b585f293', 'Yüksek Özgül İtki için Oksitleyici Zenginleştirmeli Hibrit Roket Motoru', 2, '[{"name":"Cemal Polat","order":1},{"name":"Neslihan Güler","order":2},{"name":"Asuman Kurt","order":3},{"name":"Sevil Avcı","order":4}]', 'Prof. Tuğçe Can', 'TEKNOFEST', 'Oksijen degistirici bir enjektur ve bolgelendirilmis yanma odasi tasarimiyla daha zengin oksitleyici-yakit orani kullanilarak yuksek ozgul itis elde eden deneysel bir hibrit roket motoru gelistirilmistir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('649be1eb-a461-4e57-a8b9-29849257408f', 'bf4ee98f-1fd2-418d-a62d-8cb5b585f293', 'Resif Haritalama için Düşük Maliyetli Optik AUV Sistemi', 3, '[{"name":"Tülay Aksoy","order":1},{"name":"Ragıp Erdem","order":2},{"name":"Canan Şimşek","order":3}]', 'Prof. Emre Baş', 'TEKNOFEST', 'Turkiye kiyi resiflerini katmanli 3D haritalarda belgeleyen fotogrametri ve stereo kamera tabanli dusuk maliyetli bir otonom sudalti araci sistemi gelistirilmistir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f4f0ede3-01c4-46a1-a477-acd42790683e', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Yapay Zeka Destekli Erken Yangın Tespiti', 1, '[{"name":"Saadet Tekin","order":1},{"name":"Nazan Duran","order":2},{"name":"Fuat Ateş","order":3}]', 'Prof. Arda Keçeci', 'TUBITAK-2204A', 'YOLOv8 nesne algılama modeliyle duman ve alev tespiti yapan, konvansiyonel dedektörlere kıyasla uyarı süresini yüzde kırk kısaltan düşük maliyetli kenar-bilişim yangın erken uyarı sistemi.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f5c97d0e-9bca-4e0b-a17d-a75193ef0082', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Ağır Metallerin Tarımsal Atıklarla Filtrelenmesi', 2, '[{"name":"Salih Yücel","order":1},{"name":"Gonca Boz","order":2},{"name":"Naci Çalışkan","order":3},{"name":"Dilek Peker","order":4}]', 'Prof. Umut Şahin', 'TUBITAK-2204A', 'Pirinç kabuğu ve fındık kabuğu bazlı biyosorbentlerin ağır metal (Pb, Cd, Cr) giderimini araştırır; kimyasal aktivasyon yöntemleri optimizasyonu ve adsorpsiyon kinetiği modellemesi içerir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('836703c7-94e5-4e9c-a1f4-c9aeca526cd1', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Giyilebilir Duruş Bozukluğu Uyarı Sensörü', 3, '[{"name":"Latife Kara","order":1},{"name":"Ayfer Gündüz","order":2},{"name":"Ümit Soylu","order":3},{"name":"Zeki Turan","order":4}]', 'Prof. Rüya Işık', 'TUBITAK-2204A', 'IMU füzyonu ve çevrimiçi öğrenme ile omurga açı sapmalarını gerçek zamanlı izleyen giyilebilir cihaz; haptik titreşimle anında geri bildirim sağlar ve 90 dakika pil ömrü hedefler.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('202b2597-5a44-4ae0-a6a5-4834870f87d0', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Mikroalgler ile Karbon Yakalama Sistemi', 4, '[{"name":"Perihan Çakır","order":1},{"name":"Filiz Erdoğan","order":2},{"name":"Semiha Arıcan","order":3},{"name":"Ayşe Tezcan","order":4}]', 'Prof. Zeynep Gül', 'TUBITAK-2204A', 'Kapalı devre fotobiyoreaktörde Chlorella vulgaris kültürü yetiştiren sistem; CO2 emilim kapasitesi ve biyokütle üretimi ticari karbon tutma alternatiflerine göre karşılaştırılır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('a426a611-7b78-434d-a881-aa71b5849acb', 'bb63166c-d38c-4278-a1e9-5c8b7b081a6c', 'Uydu Görüntülerinde Derin Öğrenme ile Yangın Riski Haritalaması', 1, '[{"name":"Simge Doruk","order":1},{"name":"Arzu Ünal","order":2},{"name":"Bahar Keçeci","order":3}]', 'Prof. Caner Turgut', 'TUBITAK-2204A', 'Sentinel-2 coklu-spektral uydu goruntuleri uzerinde egitilmis bir U-Net siniflandirici kullanilarak haftalik yangin riski haritalari uretilmekte ve orman yangini tehlike seviyesi geleneksel FFMC endekslerinden 23% daha erken tespit edilmektedir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('399c8138-c254-4cc4-a305-be9db396f5be', 'bb63166c-d38c-4278-a1e9-5c8b7b081a6c', 'Endüstriyel Atıksudan Ağır Metal Giderimi için Biosorpsiyon Optimizasyonu', 2, '[{"name":"Serap Işık","order":1},{"name":"Özgür Eren","order":2},{"name":"Nuran Kayalı","order":3}]', 'Prof. Hakan Kurt', 'TUBITAK-2204A', 'Tekstil ve galvaniz atiksuyu aritma icin fistik kabugu bazli bir biyosorbent optimize edilmis; 200 mg/L baslangic konsantrasyonunda bakir ve kursun icin 95% uzeri giderim verimi elde edilmistir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f70484ca-9482-441b-a0f1-a51bd61a5693', 'bb63166c-d38c-4278-a1e9-5c8b7b081a6c', 'IMU Tabanlı Giyilebilir Boyun Duruşu İzleme ve Düzeltme Sistemi', 3, '[{"name":"Kamil Taşkın","order":1},{"name":"Samet Boztepe","order":2},{"name":"Enver Aktaş","order":3}]', 'Prof. Damla Kılıç', 'TUBITAK-2204A', 'Boyun posturunu gercek zamanli olarak takip eden ve suregen yanlis postur sirasinda titresimli uyari veren 6-eksenli IMU tabanli bir boyun bandi gelistirilmis; on saatlik ofis calismasinda boyun agrisi vakasi 40% azalmistir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('bd7220da-b4dd-4ddc-acbc-cac1d9491475', '3f9cabdb-61dc-45da-afa5-dbb1747cd8c8', 'Termal Kamera ve İHA Görüntüleri ile Hızlı Orman Yangını Tespiti', 1, '[{"name":"Şerife Erbaş","order":1},{"name":"Nilüfer Yalın","order":2},{"name":"Cenk Dalkılıç","order":3}]', 'Prof. İrem Demirci', 'TUBITAK-2204A', 'Uygun maliyetli termal kameralar ve RGB drone goruntülerini birlestiren hafif bir erken yangin tespit sistemi gelistirilmis; FLIR Tau2 termal cekimleri uzerinde egitilmis YOLOv5s modeli ile 0.91 F1 skoru elde edilmistir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f5a78224-c079-428b-a9be-b4ab0c8d0f38', '3f9cabdb-61dc-45da-afa5-dbb1747cd8c8', 'Lignoselülozik Biyokütleden Ağır Metal Biyosorbent Sentezi ve Karakterizasyonu', 2, '[{"name":"Mahir Gündoğdu","order":1},{"name":"Tuba Ersoy","order":2},{"name":"Vedat Koçak","order":3},{"name":"Feride Sarıoğlu","order":4}]', 'Prof. Emre Baş', 'TUBITAK-2204A', 'Pirinc samani ve seker kamisi bagasindan alkali aktivasyonlu biyosorbentler sentezlenmis; BET ve SEM karakterizasyonu ile agir metal adsorpsiyon kapasitesi ve seciciligi endustriyel referans materyalleriyle karsilastirmali olarak belirlenmistir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('7c08441a-9b1c-43b1-ab4b-a6d204c8f90d', '6c44b363-4522-4cad-a251-06484b72b164', 'Phased Array Antenna for mmWave 5G (Team A)', 1, '[{"name":"Natalie Torres","order":1},{"name":"Mia Peterson","order":2},{"name":"Joshua Gray","order":3},{"name":"Elizabeth Ramirez","order":4}]', 'Prof. Isaac Perez', 'IEEE-APSSDC', 'Designs a 16-element phased array antenna with integrated MMIC beamforming IC for 28 GHz 5G applications, demonstrating plus-or-minus 60 degree beam steering and 24 dBi gain.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('ca11e01d-82af-4055-aa03-4640780aa91b', '6c44b363-4522-4cad-a251-06484b72b164', 'Wearable RFID Tag Antenna for Healthcare (Team B)', 2, '[{"name":"Bella James","order":1},{"name":"Zoey Watson","order":2},{"name":"Aiden Brooks","order":3},{"name":"Stella Kelly","order":4}]', 'Prof. Ethan Ward', 'IEEE-APSSDC', 'Develops a conformal RFID tag antenna for the 900 MHz UHF band, optimized for on-body performance in healthcare settings with over 3 m read range despite proximity to skin.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f587f2b0-2c8e-40bc-ac05-182f1d07cf58', '6c44b363-4522-4cad-a251-06484b72b164', 'Dual-Band Microstrip Patch Antenna (Team C)', 3, '[{"name":"Henry Sanders","order":1},{"name":"Zoe Price","order":2},{"name":"Owen Bennett","order":3},{"name":"Sofia Wood","order":4}]', 'Prof. Owen Gray', 'IEEE-APSSDC', 'Designs a dual-band microstrip patch antenna resonating at 2.4 GHz and 5.8 GHz for Wi-Fi applications, achieving over 6 dBi gain on both bands with a compact footprint.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('32f1ec66-89dc-49f5-a867-7ec816ff6d07', '6c44b363-4522-4cad-a251-06484b72b164', 'Metamaterial-based Radar Cross Section Reduction (Team D)', 4, '[{"name":"Chloe Barnes","order":1},{"name":"Liam Ross","order":2},{"name":"Ava Henderson","order":3},{"name":"Sofia Coleman","order":4}]', 'Prof. Aria Sanders', 'IEEE-APSSDC', 'Applies mushroom-type electromagnetic band-gap metamaterial structures to reduce the radar cross section of a flat metallic target by over 15 dB across the X-band (8-12 GHz).') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('558f6b14-f11f-4dc3-ad37-c9041ad4e145', '318124ea-8614-4355-ad48-2486524dfc13', '5G NR Sub-6 GHz MIMO Array with Adaptive Beam Steering (Team A)', 1, '[{"name":"Scarlett Jenkins","order":1},{"name":"Dylan Perry","order":2},{"name":"John Powell","order":3},{"name":"Landon Long","order":4}]', 'Prof. Logan Bailey', 'IEEE-APSSDC', 'Designs a 4x4 planar inverted-F antenna array for 5G NR n78 band with active beam steering, achieving 12 dBi peak gain and 99th-percentile SINR improvement over a single-element reference in a dense urban channel model.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('e970c78e-aaff-43ef-a236-77caf54b07ce', '318124ea-8614-4355-ad48-2486524dfc13', 'On-Body 2.4 GHz Patch Antenna for Implant-to-Wearable BAN Link (Team B)', 2, '[{"name":"Olivia Patterson","order":1},{"name":"Ryan Hughes","order":2},{"name":"Sebastian Flores","order":3}]', 'Prof. Ella Brooks', 'IEEE-APSSDC', 'Characterises a flexible substrate patch antenna designed for the 2.4 GHz ISM band in body-area network scenarios, measuring path loss and SAR distribution across five tissue-equivalent phantom torso configurations.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('9c450cf6-cae4-4390-a3ed-12f231962d02', '318124ea-8614-4355-ad48-2486524dfc13', 'Wideband Yagi-Uda Array for UHF TV White-Space Cognitive Radio (Team C)', 3, '[{"name":"Emma Washington","order":1},{"name":"Samuel Butler","order":2},{"name":"Alexander Simmons","order":3}]', 'Prof. Nolan Davies', 'IEEE-APSSDC', 'Designs a compact 3-element Yagi-Uda array covering 470-790 MHz UHF TV white-space bands, demonstrating 8 dBd gain with a reconfigurable matching network enabling cognitive radio spectrum sensing across sub-bands.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('55964658-c936-45e8-ae7c-bccdb9dcfb20', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', '60 GHz Millimetre-Wave Slot Array Antenna for Short-Range P2P Links (Team A)', 1, '[{"name":"Addison Foster","order":1},{"name":"William Gonzales","order":2},{"name":"Victoria Bryant","order":3}]', 'Prof. Sophie Clarke', 'IEEE-APSSDC', 'Designs an 8x1 slot array antenna resonating at 60 GHz for IEEE 802.11ad point-to-point links, achieving 18 dBi gain and 3-dB beamwidth of 12 degrees with a low-cost Rogers substrate and SMA end-launch connector.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('bc3fe67d-937f-4744-ae90-a19293fc5d5c', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', 'Electrotextile Antenna for 915 MHz BodyArea Network (Team B)', 2, '[{"name":"Noah Alexander","order":1},{"name":"Ella Russell","order":2},{"name":"Daniel Griffin","order":3}]', 'Prof. Julian Hayes', 'IEEE-APSSDC', 'Fabricates and characterises a washable conductive-thread patch antenna on a cotton substrate for 915 MHz ISM BAN applications, measuring detuning under bending and 10 wash cycles with a Vector Network Analyser.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('7409c3d5-b62b-487e-aa60-8be8b736f7d9', '47979751-163d-48b3-ae56-a65586d18f1b', 'Autogyro Payload Recovery System - Entry 1', 1, '[{"name":"Hazel Diaz","order":1},{"name":"Charles Hayes","order":2},{"name":"Lincoln Myers","order":3}]', 'Prof. Aurora Price', 'CANSAT-2025', 'Designs a passive autogyro descent mechanism for a CanSat payload, achieving under 5 m/s terminal velocity without motorized components using only rotating blade geometry.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('d812e821-9cf5-4042-ae7b-7b45b9a7b922', '47979751-163d-48b3-ae56-a65586d18f1b', 'Telemetry and Ground Station Integration - Entry 2', 2, '[{"name":"Camila Ford","order":1},{"name":"Mason Hamilton","order":2},{"name":"Matthew Graham","order":3},{"name":"Benjamin Sullivan","order":4}]', 'Prof. Hazel Foster', 'CANSAT-2025', 'Implements a dual-frequency telemetry system (433 MHz and 2.4 GHz) with a custom ground station GUI displaying real-time GPS track, altitude profile, and sensor dashboards.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('e3603c93-8069-4824-afa0-10fe733475e3', '47979751-163d-48b3-ae56-a65586d18f1b', 'Atmospheric Sensor Suite Deployment - Entry 3', 3, '[{"name":"Evelyn Wallace","order":1},{"name":"Anthony Woods","order":2},{"name":"Alice Cole","order":3}]', 'Prof. Mia Howard', 'CANSAT-2025', 'Integrates a miniaturized atmospheric sensor suite measuring temperature, humidity, CO2, and particulate matter into a CanSat form factor with in-flight data logging and post-flight visualization.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('851c3941-dfa8-4feb-ae26-c58965626732', '47979751-163d-48b3-ae56-a65586d18f1b', 'Deployable Heat Shield for Reentry Demo - Entry 4', 4, '[{"name":"Madeline West","order":1},{"name":"Aubrey Jordan","order":2},{"name":"Jaxon Owens","order":3},{"name":"Isabella Reynolds","order":4}]', 'Prof. Lucy Brooks', 'CANSAT-2025', 'Designs a lightweight deployable ablative heat shield for a CanSat reentry demonstration, validating thermal protection material performance and deployment mechanism reliability during descent.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('bfe219aa-e626-4093-acb4-0a8d92229438', '10abd4e8-0cb9-4853-a17c-ac40da311bff', 'Variable-Pitch Autogyro for Precision Landing in Turbulent Descent', 1, '[{"name":"Luke Fisher","order":1},{"name":"Aaliyah Ellis","order":2},{"name":"Diana Smith","order":3}]', 'Prof. Owen Gray', 'CANSAT-2025', 'Develops a variable-pitch autogyro recovery mechanism enabling a CanSat to achieve a target landing zone within a 10 m radius under 5 m/s crosswind conditions, validated through six consecutive drop tests.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('667b7df9-720b-44ea-a5c0-47ee35ca31b7', '10abd4e8-0cb9-4853-a17c-ac40da311bff', 'Real-Time Compressed Telemetry over 915 MHz FHSS for CanSat Network', 2, '[{"name":"Alexander Johnson","order":1},{"name":"Grace Williams","order":2},{"name":"Edward Brown","order":3}]', 'Prof. Lucas Sullivan', 'CANSAT-2025', 'Implements a frequency-hopping spread-spectrum telemetry link at 915 MHz with LZ4-compressed sensor payloads, achieving 98.4% packet delivery ratio at 1 km slant range with a custom SDL ground-station receiver.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('77459bde-2dda-4848-a5c5-22decb273d5e', '10abd4e8-0cb9-4853-a17c-ac40da311bff', 'Multi-Layer Atmospheric Temperature and Humidity Profiling CanSat', 3, '[{"name":"George Jones","order":1},{"name":"Clara Garcia","order":2},{"name":"Elena Miller","order":3}]', 'Prof. Caleb Richardson', 'CANSAT-2025', 'Deploys a CanSat equipped with cascaded SHT31 and BMP390 sensors sampling at 10 Hz during descent, generating a vertical atmospheric profile and validating results against radiosonde reference data from a nearby weather station.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('8b01cc7c-13ab-422f-adc9-8a0a796c8dc4', '9f49cd18-d850-4b1e-ae53-c08253910f4e', 'Two-Blade Autogyro with Impact-Resistant Composite Shell Recovery System', 1, '[{"name":"Fiona Davis","order":1},{"name":"Natalie Wilson","order":2},{"name":"Robert Taylor","order":3}]', 'Prof. Dylan Reed', 'CANSAT-2025', 'Constructs a two-blade autogyro from CFRP blades and a 3D-printed polycarbonate nacelle, characterising rotor RPM and descent rate across three payload weights and demonstrating sub-5 m/s terminal velocity at 500 g gross mass.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('15713af0-a06b-43ac-a10b-867a682f2409', '9f49cd18-d850-4b1e-ae53-c08253910f4e', 'Ground Control Station with Live 3D Trajectory Visualisation', 2, '[{"name":"William Anderson","order":1},{"name":"Charles Thomas","order":2},{"name":"Sophie Jackson","order":3},{"name":"Arthur White","order":4}]', 'Prof. Eva Harding', 'CANSAT-2025', 'Develops a Python-based ground control station parsing serial telemetry from a CanSat via a 433 MHz link, rendering a live 3D trajectory in CesiumJS and generating automatic flight-report PDFs on recovery event detection.') ON CONFLICT DO NOTHING;
